import { task, wait, logger } from "@trigger.dev/sdk/v3";

export const approvalTask = task({
  id: "approvalTask-human_in_the_loop_approval__XiX6kXT",
  run: async (payload: any) => {
    logger.info("Requesting approval...");

    const token = await wait.createToken({ timeout: "1h" });
    logger.info(token.id);

    const result = await wait.forToken<{ approved: boolean }>(token.id);

    if (result.ok && result.output.approved) {
      logger.info("Request approved!");
    } else {
      logger.info("Request rejected.");
    }
  },
});

